const data = $('Parse_Slots').item.json;
const question = data.followup_question || "예약에 필요한 정보를 알려주세요.";

return [{json: {
  version: "2.0",
  template: {
    outputs: [{ simpleText: { text: question } }]
  }
}}];

const data = $json;
const reason = data.reason || "예약이 불가합니다.";
const recommendations = data.recommendations || [];

let recText = recommendations.length > 0
  ? "\n\n대신 예약 가능한 시간대:\n" + recommendations.join(" / ")
  : "\n\n다른 날짜나 시간을 알려주시면 다시 확인해드릴게요.";

const text = "죄송합니다. " + reason + recText;

return [{json: {
  version: "2.0",
  template: {
    outputs: [{ simpleText: { text: text } }]
  }
}}];

// Parse_Slots에서 슬롯 직접 가져오기
const slots = $('Parse_Slots').item.json;

// Get_ShopInfo_Booking에서 shopInfo 가져오기
const shopInfo = $('Get_ShopInfo_Booking').item.json.data || $('Get_ShopInfo_Booking').item.json;
const depositAmount = shopInfo.deposit_amount || 0;

// service_durations 파싱: "젤네일 60분 / 기본네일 45분 / 페디큐어 60분"
const FALLBACK_DURATIONS = {"GEL_BASIC": 30, "GEL_NAIL": 60, "PEDICURE": 60};
const NAME_TO_CODE = {"젤네일": "GEL_NAIL", "기본네일": "GEL_BASIC", "페디큐어": "PEDICURE"};
let serviceDurations = {...FALLBACK_DURATIONS};
try {
  if (shopInfo.service_durations) {
    const parsed = {};
    shopInfo.service_durations.split(' / ').forEach(part => {
      const [name, minStr] = part.trim().split(' ');
      const code = NAME_TO_CODE[name];
      if (code) parsed[code] = parseInt(minStr);
    });
    if (Object.keys(parsed).length > 0) serviceDurations = parsed;
  }
} catch(e) {}

// Get_Schedule에서 스케줄 데이터 가져오기
const scheduleData = $('Get_Schedule').item.json.data || $('Get_Schedule').item.json;
const businessHourStr = scheduleData.business_hour;
const bookedSchedules = scheduleData.booked_schedules || [];

// end time 계산
const duration = (serviceDurations[slots.service_code] || 60) + (slots.off_removal ? 30 : 0);

const [startH, startM] = slots.reserve_time.split(':').map(Number);
const endTotalMin = startH * 60 + startM + duration;
const endH = Math.floor(endTotalMin / 60);
const endM = endTotalMin % 60;
const reserve_time_end = String(endH).padStart(2, '0') + ':' + String(endM).padStart(2, '0');

const serviceNames = {"GEL_NAIL": "젤네일", "GEL_BASIC": "기본네일", "PEDICURE": "페디큐어"};

const slotsObj = {
  name: slots.name,
  phone_num: slots.phone_num,
  reserve_date: slots.reserve_date,
  reserve_time: slots.reserve_time,
  reserve_time_end: reserve_time_end,
  service_code: slots.service_code,
  service_name: serviceNames[slots.service_code] || slots.service_code,
  off_removal: slots.off_removal,
  past_visit: slots.past_visit
};

// 요일 체크 (월요일 = 1)
const date = new Date(slots.reserve_date);
const dayOfWeek = date.getDay();
if (dayOfWeek === 1) {
  return [{json: {valid: false, reason: "정기 휴무일(월요일)입니다.", recommendations: [], duration: duration, slots: slotsObj}}];
}

// 영업시간 파싱
const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const lines = businessHourStr.split(/\\n|\n/);
let startTime = "10:00", endTime = "22:00";
try {
  const line = lines.find(l => l.includes(isWeekend ? '주말' : '평일'));
  const range = line.split(': ')[1];
  [startTime, endTime] = range.split('-');
} catch(e) {}

const toMin = t => {
  const [h, m] = t.trim().split(':').map(Number);
  return h * 60 + m;
};

const openMin = toMin(startTime);
const closeMin = toMin(endTime);
const reqStart = toMin(slots.reserve_time);
const reqEnd = reqStart + duration;

// 영업시간 체크
if (reqStart < openMin || reqEnd > closeMin) {
  return [{json: {
    valid: false,
    reason: "영업시간(" + startTime + "~" + endTime + ") 외의 시간입니다.",
    recommendations: [],
    duration: duration,
    slots: slotsObj
  }}];
}

// 예약 충돌 체크
let hasConflict = false;
for (const slot of bookedSchedules) {
  const [slotStart, slotEnd] = slot.reserve_time.split('-');
  const s = toMin(slotStart);
  const e = toMin(slotEnd);
  if (reqStart < e && s < reqEnd) {
    hasConflict = true;
    break;
  }
}

// 추천 시간대 계산 (충돌 여부와 관계없이 항상 실행)
const timelineSize = closeMin - openMin;
if (isNaN(timelineSize) || timelineSize <= 0) {
  return [{json: {
    valid: false,
    reason: "영업시간 확인 중 오류가 발생했습니다.",
    recommendations: [],
    duration: duration,
    slots: slotsObj
  }}];
}

const timeline = new Array(timelineSize).fill(0);
for (const slot of bookedSchedules) {
  const [slotStart, slotEnd] = slot.reserve_time.split('-');
  const s = toMin(slotStart) - openMin;
  const e = toMin(slotEnd) - openMin;
  for (let i = Math.max(0, s); i < Math.min(timeline.length, e); i++) {
    timeline[i] = 1;
  }
}

const recommendations = [];
let count = 0;
for (let i = 0; i < timeline.length; i++) {
  if (timeline[i] === 0) {
    count++;
    if (count >= duration && (i - duration + 1 + openMin) % 30 === 0) {
      const sMin = i - duration + 1 + openMin;
      recommendations.push(
        String(Math.floor(sMin / 60)).padStart(2, '0') + ':' + String(sMin % 60).padStart(2, '0')
      );
    }
  } else {
    count = 0;
  }
}

// 충돌 시 valid: false + recommendations 포함 반환
if (hasConflict) {
  return [{json: {
    valid: false,
    reason: "해당 시간에 이미 예약이 있습니다.",
    recommendations: recommendations.slice(0, 3),
    duration: duration,
    slots: slotsObj
  }}];
}

return [{json: {
  valid: true,
  reason: "예약 가능합니다.",
  duration: duration,
  deposit_amount: depositAmount,
  slots: slotsObj,
  recommendations: recommendations.slice(0, 3)
}}];

const raw = $('Intake Agent').item.json.output;
let parsed;

try {
  const p = typeof raw === 'string' ? JSON.parse(raw) : raw;
  parsed = p.output || p;
} catch(e) {
  parsed = { intent: 'unknown', slots: {}, missing_fields: [], followup_question: null, response: '' };
}

const slots = parsed.slots || {};

// Prepare_Input에서 기존 고객 정보 가져오기
const prepareData = $('Prepare_Input').first().json;

// 날짜 형식 검증 (YYYY-MM-DD만 허용)
const isValidDate = (d) => d && /^\d{4}-\d{2}-\d{2}$/.test(d);
// 시간 형식 검증 (HH:MM만 허용)
const isValidTime = (t) => t && /^\d{2}:\d{2}$/.test(t);

// 기존 고객이면 DB 값으로 보완
const name = slots.name || prepareData.name || null;
const phone_num = slots.phone_num || prepareData.phone_num || null;
const reserve_date = isValidDate(slots.reserve_date) ? slots.reserve_date : null;
const reserve_time = isValidTime(slots.reserve_time) ? slots.reserve_time : null;
const service_code = slots.service_code || null;
const off_removal = slots.off_removal !== undefined && slots.off_removal !== null ? slots.off_removal : null;
const past_visit = slots.past_visit !== undefined && slots.past_visit !== null ? slots.past_visit : null;

// booking일 때 missing_fields 직접 재계산
let missing_fields = [];
if (parsed.intent === 'booking') {
  if (!name) missing_fields.push('name');
  if (!phone_num) missing_fields.push('phone_num');
  if (off_removal === null) missing_fields.push('off_removal');
  if (!reserve_date) missing_fields.push('reserve_date');
  if (!reserve_time) missing_fields.push('reserve_time');
  if (!service_code) missing_fields.push('service_code');
  if (past_visit === null) missing_fields.push('past_visit');
} else {
  missing_fields = parsed.missing_fields || [];
}

// 누락 필드별 라벨 및 질문
const fieldLabels = {
  'name': '성함',
  'phone_num': '전화번호 (010-XXXX-XXXX)',
  'off_removal': '젤 제거 여부 (O/X)',
  'reserve_date': '예약 희망 날짜 (YYYY-MM-DD)',
  'reserve_time': '예약 희망 시간 (HH:MM)',
  'service_code': '시술 종류 (젤네일/기본네일/페디큐어)',
  'past_visit': '과거 방문 경험 (O/X)'
};

const specificQuestions = {
  'name': '성함을 알려주세요.',
  'phone_num': '전화번호를 알려주세요. (예: 010-1234-5678)',
  'off_removal': '젤 제거가 필요하신가요? (O/X)',
  'reserve_date': '예약 희망 날짜를 알려주세요. (예: 2026-05-23)',
  'reserve_time': '예약 희망 시간을 알려주세요. (예: 14:00)',
  'service_code': '시술 종류를 알려주세요. (젤네일/기본네일/페디큐어)',
  'past_visit': '이전에 방문하신 적이 있으신가요? (O/X)'
};

let followup_question = null;
if (parsed.intent === 'booking' && missing_fields.length > 0) {
  if (missing_fields.length === 1) {
    const field = missing_fields[0];
    followup_question = specificQuestions[field] || `${fieldLabels[field]}을 알려주세요.`;
  } else {
    const missingLabels = missing_fields.map(f => fieldLabels[f] || f);
    followup_question = `아래 정보를 알려주세요:\n${missingLabels.map(l => `- ${l}`).join('\n')}`;
  }
}

return [{json: {
  intent: parsed.intent,
  name,
  phone_num,
  reserve_date,
  reserve_time,
  service_code,
  off_removal,
  past_visit,
  missing_fields,
  followup_question,
  response: parsed.response || ''
}}];

const kakaoData = $('Kakao_Webhook').item.json.body;
const lookupResult = $('HTTP Request').item.json;

const kakaoUserId = kakaoData.userRequest.user.id;
const plusfriendUserKey = kakaoData.userRequest.user.properties.plusfriendUserKey; // 추가
const utterance = kakaoData.userRequest.utterance;
const today = new Date().toISOString().split('T')[0];

const isExisting = lookupResult.data?.is_existing || false;
const name = isExisting ? lookupResult.data?.name : null;
const phoneNum = isExisting ? lookupResult.data?.phone_num : null;

return [{json: {
  kakao_user_id: kakaoUserId,
  plusfriend_user_key: plusfriendUserKey,  // 추가
  utterance: utterance,
  today: today,
  name: name,
  phone_num: phoneNum,
  is_existing: isExisting
}}];

const bookingsData = $input.item.json.data || $input.item.json;
const bookings = bookingsData.bookings || [];

// Intake Agent에서 name 추출
let userName = null;
try {
  const intakeRaw = $('Intake Agent').first().json.output;
  const intake = JSON.parse(intakeRaw);
  userName = intake.slots?.name || null;
} catch(e) {}

// 이름 없으면 Prepare_Input(DB)에서 보완
if (!userName) {
  userName = $('Prepare_Input').first().json.name || null;
}

const today = new Date().toISOString().split('T')[0];

let match = null;
if (userName) {
  const candidates = bookings.filter(b =>
    b.name === userName &&
    b.reserve_date >= today &&
    b.visit_status !== 'CANCELLED'
  );
  match = candidates.sort((a, b) => a.reserve_date.localeCompare(b.reserve_date))[0] || null;
}

if (match) {
  return [{json: {
    found: true,
    reservation_id: match.id,
    customer_name: match.name,
    service: match.service,
    reserve_date: match.reserve_date,
    reserve_time: match.reserve_time,
    off_removal: match.off_removal,
    visit_status: match.visit_status
  }}];
} else {
  return [{json: { found: false, customer_name: userName }}];
}

let intent = 'cancel';
let name = null;
try {
  const intakeRaw = $('Intake Agent').first().json.output;
  const intake = JSON.parse(intakeRaw);
  intent = intake.intent || 'cancel';
  name = intake.slots?.name || null;
} catch(e) {}

const intentLabel = intent === 'cancel' ? '취소' : '변경';

let text;
if (!name) {
  text = `예약 ${intentLabel}을 도와드리겠습니다. 예약하실 때 사용하신 성함을 알려주세요.`;
} else {
  text = `'${name}'님 명의의 예약을 찾을 수 없습니다. 성함을 다시 확인해 주세요.`;
}

return [{json: {
  version: "2.0",
  template: {
    outputs: [{
      simpleText: { text }
    }]
  }
}}];

const existing = $('Find_My_Reservation').first().json;
const slots = $input.item.json;

let intentSlots = {};
try {
  const intakeRaw = $('Intake Agent').first().json.output;
  intentSlots = JSON.parse(intakeRaw).slots || {};
} catch(e) {}

const shopInfo = $('Get_ShopInfo_CC').first().json.data || $('Get_ShopInfo_CC').first().json;
const depositAmount = shopInfo.deposit_amount || 0;

const FALLBACK_DURATIONS = {"GEL_NAIL": 60, "GEL_BASIC": 45, "PEDICURE": 60};
const NAME_TO_CODE = {"젤네일": "GEL_NAIL", "기본네일": "GEL_BASIC", "페디큐어": "PEDICURE"};
let serviceDurations = {...FALLBACK_DURATIONS};
try {
  if (shopInfo.service_durations) {
    const parsed = {};
    shopInfo.service_durations.split(' / ').forEach(part => {
      const [name, minStr] = part.trim().split(' ');
      const code = NAME_TO_CODE[name];
      if (code) parsed[code] = parseInt(minStr);
    });
    if (Object.keys(parsed).length > 0) serviceDurations = parsed;
  }
} catch(e) {}

const serviceNames = {"GEL_NAIL": "젤네일", "GEL_BASIC": "기본네일", "PEDICURE": "페디큐어"};

const service_code = intentSlots.service_code || null;
const service = service_code ? (serviceNames[service_code] || existing.service) : existing.service;
const off_removal = (intentSlots.off_removal !== null && intentSlots.off_removal !== undefined) ? intentSlots.off_removal : existing.off_removal;
const reserve_date = intentSlots.reserve_date || existing.reserve_date;

let reserve_time, estimated_duration_min;

if (intentSlots.reserve_time) {
  const duration = (serviceDurations[service_code] || 60) + (off_removal ? 30 : 0);
  const [h, m] = intentSlots.reserve_time.split(':').map(Number);
  const endMin = h * 60 + m + duration;
  const endTime = String(Math.floor(endMin / 60)).padStart(2, '0') + ':' + String(endMin % 60).padStart(2, '0');
  reserve_time = intentSlots.reserve_time + '-' + endTime;
  estimated_duration_min = duration;
} else {
  reserve_time = existing.reserve_time;
  const [startStr, endStr] = existing.reserve_time.split('-');
  const [sh, sm] = startStr.split(':').map(Number);
  const [eh, em] = endStr.split(':').map(Number);
  estimated_duration_min = (eh * 60 + em) - (sh * 60 + sm);
}

return [{json: {
  reservation_id: existing.reservation_id,
  body: {
    service: service,
    designer: "사장님",
    reserve_date: reserve_date,
    reserve_time: reserve_time,
    estimated_duration_min: estimated_duration_min,
    off_removal: off_removal,
    deposit_amount: depositAmount,
    visit_status: "CONFIRMED"
  }
}}];

const patch = $('Build_Patch').first().json;
const startTime = patch.body.reserve_time.split('-')[0];

return [{json: {
  version: "2.0",
  template: {
    outputs: [{
      simpleText: {
        text: `예약이 변경되었습니다! ✅\n\n📅 날짜: ${patch.body.reserve_date}\n⏰ 시간: ${startTime}\n💅 시술: ${patch.body.service}`
      }
    }]
  }
}}];

const existing = $('Find_My_Reservation').first().json;
const startTime = existing.reserve_time.split('-')[0];

return [{json: {
  version: "2.0",
  template: {
    outputs: [{
      simpleText: {
        text: `${existing.customer_name}님의 예약이 취소되었습니다. 😢\n\n취소된 예약:\n📅 ${existing.reserve_date} ${startTime}\n💅 ${existing.service}\n\n또 방문해 주세요!`
      }
    }]
  }
}}];

const authHeader = $input.item.json.headers?.authorization || "";
const body = $input.item.json.body;

// 임시: 항상 통과 (디버깅용)
return [{json: {
  isValid: true,
  authHeader: authHeader,  // 실제 값 확인용
  body: body
}}];

const webhookBody = $('Verify_Signature').item.json.body;

// Get_Payment 대신 webhook body에서 직접 읽기
const status = webhookBody.data?.status;
const paidAmount = webhookBody.data?.totalAmount;
const paymentKey = webhookBody.data?.paymentKey;
const orderId = webhookBody.data?.orderId;

const isSuccess = status === "DONE";

// 임시 하드코딩 - 테스트용
return [{json: {
  isSuccess: true,
  status: "DONE",
  paymentKey: "test_payment_key_hardcoded_3",  // ← 다른 값으로 변경
  orderId: "booking_2",
  paidAmount: 5000
}}];


