// 우선순위: DB에 저장된 이름 → 카카오 닉네임 → 기본값
const customerName = prepareData.name 
  || kakaoProps.nickname 
  || '고객님';

return [{json: { 
  waiting: true, 
  customer_name: customerName 
}}];

const bookings = $json.data?.bookings || [];
const customerName = $('Prepare_Input').first().json.name;

// 이름으로 필터 + 가장 최근 예약의 paymentStatus 확인
const myBooking = bookings
  .filter(b => b.name === customerName)
  .sort((a, b) => new Date(b.reserveDate) - new Date(a.reserveDate))[0];

const isPaid = myBooking?.payment_status === 'PAID';

return [{json: { isPaid, booking: myBooking || null }}];
